    // Mutating ("write") path. Mirrors Roslyn's RequestExecutionQueue handling of
    // MutatesSolutionState=true requests: the gate is held for the whole (brief,
    // parse-only) body so the mutation is fully applied before any later request
    // captures its snapshot. didOpen/didChange/didSave/didClose/watchedFiles use this.
    private async Task<T> GuardAsync<T>(Func<T> body, [System.Runtime.CompilerServices.CallerMemberName] string caller = null)
    {
        await this.gate.WaitAsync().ConfigureAwait(false);
        try
        {
            try
            {
                return body();
            }
            catch (OperationCanceledException)
            {
                throw;
            }
            catch (Exception ex)
            {
                // Issue #816: handler crashes (e.g., NRE deep in symbol resolution when
                // editing a file whose syntax outpaces the bundled LS) used to surface as
                // a per-request "Object reference not set to an instance of an object"
                // popup for every diagnostic / inlayHint / codeLens / semanticTokens pull
                // until the user restarted the editor. Swallow the exception, log it to
                // stderr for diagnosis, and return a safe default (null for reference
                // types — LSP clients treat that as "no result" rather than an error).
                LogHandlerException(caller, ex);
                return default;
            }
        }
        finally
        {
            this.gate.Release();
        }
    }

    // Non-mutating ("read") path. Mirrors Roslyn's RequestExecutionQueue handling of
    // non-mutating requests: the request's snapshot (here, the immutable DocumentContent)
    // is captured serially under the gate so it reflects every prior mutation, and the
    // gate is held only for that O(1) capture. The actual computation then runs OFF the
    // gate on the thread pool via Task.Run so that:
    //   * concurrent read requests never serialize behind one another, and
    //   * a long-running read (e.g. the first cold full-workspace bind, ~17s on a large
    //     workspace) never blocks unrelated reads or, crucially, a didChange while typing.
    // Roslyn likewise dispatches non-mutating work via Task.Run "to enforce parallelizability".
    // CancellationToken is honored end-to-end: StreamJsonRpc maps the LSP $/cancelRequest
    // notification onto this token, so superseded hovers/highlights abort instead of
    // consuming a thread-pool thread to completion.
    private async Task<T> ReadDocumentAsync<T>(
        TextDocumentIdentifier identifier,
        Func<DocumentContent, CancellationToken, T> compute,
        T missing,
        CancellationToken cancellationToken,
        [System.Runtime.CompilerServices.CallerMemberName] string caller = null)
    {
        DocumentContent content;
        try
        {
            await this.gate.WaitAsync(cancellationToken).ConfigureAwait(false);
            try
            {
                if (!this.TryGet(identifier, out content) || content == null)
                {
                    return missing;
                }
            }
            finally
            {
                this.gate.Release();
            }
        }
        catch (OperationCanceledException)
        {
            throw;
        }
        catch (Exception ex)
        {
            // Issue #816: even the snapshot lookup can throw (a faulted content service).
            // Degrade to "no result" rather than surfacing an error popup to the client.
            LogHandlerException(caller, ex);
            return missing;
        }

        return await Task.Run(
            () =>
            {
                try
                {
                    cancellationToken.ThrowIfCancellationRequested();
                    return compute(content, cancellationToken);
                }
                catch (OperationCanceledException)
                {
                    throw;
                }
                catch (Exception ex)
                {
                    LogHandlerException(caller, ex);
                    return missing;
                }
            },
            cancellationToken).ConfigureAwait(false);
    }

    // Non-mutating read over the whole open-document set (workspace symbols, test
    // discovery). The document list is snapshotted under the gate, then enumerated and
    // computed off the gate, identical in spirit to <see cref="ReadDocumentAsync{T}"/>.
    private async Task<T> ReadWorkspaceAsync<T>(
        Func<IReadOnlyList<KeyValuePair<string, DocumentContent>>, CancellationToken, T> compute,
        T missing,
        CancellationToken cancellationToken,
        [System.Runtime.CompilerServices.CallerMemberName] string caller = null)
    {
        IReadOnlyList<KeyValuePair<string, DocumentContent>> documents;
        try
        {
            await this.gate.WaitAsync(cancellationToken).ConfigureAwait(false);
            try
            {
                documents = this.documentContentService.AllDocuments.ToList();
            }
            finally
            {
                this.gate.Release();
            }
        }
        catch (OperationCanceledException)
        {
            throw;
        }
        catch (Exception ex)
        {
            LogHandlerException(caller, ex);
            return missing;
        }

        return await Task.Run(
            () =>
            {
                try
                {
                    cancellationToken.ThrowIfCancellationRequested();
                    return compute(documents, cancellationToken);
                }
                catch (OperationCanceledException)
                {
                    throw;
                }
                catch (Exception ex)
                {
                    LogHandlerException(caller, ex);
                    return missing;
                }
            },
            cancellationToken).ConfigureAwait(false);
    }

    private static SemanticTokens EmptySemanticTokens()
        => new SemanticTokens { Data = System.Collections.Immutable.ImmutableArray<int>.Empty };

    private static void LogHandlerException(string handler, Exception ex)
    {
        try
        {
            Console.Error.WriteLine($"[gsharp-lsp] {handler ?? "handler"} failed: {ex.GetType().FullName}: {ex.Message}");
            Console.Error.WriteLine(ex.StackTrace);
        }
        catch
        {
            // Logging is best-effort; never let a stderr write tear down the server.
        }
    }

    private bool TryGet(TextDocumentIdentifier identifier, out DocumentContent content)
    {
        content = null;
        var uri = identifier?.Uri;
        return uri != null && this.documentContentService.TryGet(uri.ToString(), out content);
    }

    private void UpdateDocument(DocumentUri uri, string text)
    {
        var filePath = uri.GetFileSystemPath();
        var project = !string.IsNullOrEmpty(filePath) ? this.workspaceState.GetProjectForFile(filePath) : null;
        if (project != null)
        {
            project.UpdateFile(filePath, text);
        }

        // Parse-only content (no binding) feeds the content service used by other features;
        // diagnostics are produced on demand by the textDocument/diagnostic pull handler.
        var result = DocumentSyncHandler.ComputeDiagnostics(text, skipBinding: true, project, filePath, this.workspaceState);
        this.documentContentService.AddOrUpdate(uri.ToString(), result.Content);
    }

    private void PublishDiagnosticsIfPushMode(DocumentUri uri, string text, bool skipBinding)
    {
        // Clients advertising pull diagnostics request them via textDocument/diagnostic, so push
        // is suppressed to avoid double reporting. Older push-only clients still get notifications.
        if (this.clientSupportsPullDiagnostics)
        {
            return;
        }

        var filePath = uri.GetFileSystemPath();
        var project = !string.IsNullOrEmpty(filePath) ? this.workspaceState.GetProjectForFile(filePath) : null;
        var result = DocumentSyncHandler.ComputeDiagnostics(text, skipBinding, project, filePath, this.workspaceState);

        this.rpc?.NotifyWithParameterObjectAsync(
            "textDocument/publishDiagnostics",
            new PublishDiagnosticsParams { Uri = uri, Diagnostics = result.Diagnostics });
    }

    private void DetectClientDiagnosticCapabilities(JsonElement capabilities)
    {
        try
        {
            if (capabilities.ValueKind == JsonValueKind.Object)
            {
                if (capabilities.TryGetProperty("textDocument", out var textDocument)
                    && textDocument.ValueKind == JsonValueKind.Object
                    && textDocument.TryGetProperty("diagnostic", out var diagnostic)
                    && diagnostic.ValueKind == JsonValueKind.Object)
                {
                    this.clientSupportsPullDiagnostics = true;
                }

                if (capabilities.TryGetProperty("workspace", out var workspace)
                    && workspace.ValueKind == JsonValueKind.Object
                    && workspace.TryGetProperty("diagnostics", out var wsDiagnostics)
                    && wsDiagnostics.ValueKind == JsonValueKind.Object
                    && wsDiagnostics.TryGetProperty("refreshSupport", out var refreshSupport)
                    && refreshSupport.ValueKind == JsonValueKind.True)
                {
                    this.clientSupportsDiagnosticRefresh = true;
                }
            }
        }
        catch
        {
            // Capability probing is best-effort; absence of pull support falls back to push.
        }
    }

    private void RequestDiagnosticRefresh(DocumentUri changedUri)
    {
        if (!this.clientSupportsPullDiagnostics || !this.clientSupportsDiagnosticRefresh)
        {
            return;
        }

        // Single-file edits do not affect other documents, so skip refreshes for documents that
        // are not part of a multi-file project.
        var filePath = changedUri.GetFileSystemPath();
        var project = !string.IsNullOrEmpty(filePath) ? this.workspaceState.GetProjectForFile(filePath) : null;
        if (project == null || project.SourceFiles.Count <= 1)
        {
            return;
        }

        this.RequestDiagnosticRefresh();
    }

    private void RequestDiagnosticRefresh()
    {
        if (!this.clientSupportsDiagnosticRefresh)
        {
            return;
        }

        // Debounce: coalesce bursts of changes into a single workspace/diagnostic/refresh request.
        lock (this.refreshLock)
        {
            this.refreshTimer ??= new Timer(_ => this.SendDiagnosticRefresh(), null, Timeout.Infinite, Timeout.Infinite);
            this.refreshTimer.Change(500, Timeout.Infinite);
        }
    }

    private void SendDiagnosticRefresh()
    {
        try
        {
            this.rpc?.InvokeAsync("workspace/diagnostic/refresh");
        }
        catch
        {
            // The client may have disconnected; refresh is best-effort.
        }
    }

    private static string ComputeResultId(IReadOnlyList<Diagnostic> diagnostics)
    {
        var builder = new StringBuilder();
        foreach (var d in diagnostics)
        {
            builder.Append((int)d.Severity).Append('|');
            if (d.Range != null)
            {
                builder.Append(d.Range.Start?.Line).Append(',').Append(d.Range.Start?.Character).Append('-')
                    .Append(d.Range.End?.Line).Append(',').Append(d.Range.End?.Character);
            }

            builder.Append('|').Append(d.Code?.Value).Append('|').Append(d.Message).Append('\n');
        }

        var bytes = SHA256.HashData(Encoding.UTF8.GetBytes(builder.ToString()));
        return Convert.ToHexString(bytes);
    }

    private SemanticTokens ComputeSemanticTokens(DocumentContent content)
    {
        var document = new SemanticTokensDocument(SemanticTokensHandler.Legend);
        var builder = document.Create();
        SemanticTokensComputer.Tokenize(builder, content);
        builder.Commit();
        return document.GetSemanticTokens();
    }

    private TextEdit[] FormatDocument(DocumentContent content)
    {
        var sourceText = content.SyntaxTree.Text;
        var originalText = sourceText.ToString();
        var formatted = FormattingEngine.Format(originalText);
        if (formatted == originalText)
        {
            return Array.Empty<TextEdit>();
        }

        var lastLine = sourceText.Lines.Length - 1;
        var lastChar = sourceText.Lines[lastLine].Length;
        return new[]
        {
            new TextEdit
            {
                Range = new Range(new Position(0, 0), new Position(lastLine, lastChar)),
                NewText = formatted,
            },
        };
    }

    private Range ComputePrepareRename(DocumentContent content, PrepareRenameParams request)
    {
        var offset = SemanticLookup.ToOffset(content, request.Position);
        var token = SemanticLookup.FindTokenAt(content.SyntaxTree, offset);
        if (token == null || token.Kind != SyntaxKind.IdentifierToken)
        {
            return null;
        }

        var compilation = TryGetCompilation(content);
        if (compilation == null)
        {
            return null;
        }

        var symbol = SemanticLookup.ResolveSymbol(compilation, token);
        return SemanticLookup.CanRename(symbol) ? SemanticLookup.ToRange(token) : null;
    }

    private Location[] ComputeImplementation(DocumentContent content, ImplementationParams request)
    {
        var offset = SemanticLookup.ToOffset(content, request.Position);
        var token = SemanticLookup.FindTokenAt(content.SyntaxTree, offset);
        if (token == null || token.Kind != SyntaxKind.IdentifierToken)
        {
            return Array.Empty<Location>();
        }

        var compilation = TryGetCompilation(content);
        if (compilation == null)
        {
            return Array.Empty<Location>();
        }

        var symbol = SemanticLookup.ResolveSymbol(compilation, token);
        if (symbol is not InterfaceSymbol iface)
        {
            return Array.Empty<Location>();
        }

        var locations = new List<Location>();
        foreach (var structSym in compilation.GlobalScope.Structs)
        {
            if (structSym.Interfaces.Contains(iface) && structSym.Declaration != null)
            {
                locations.Add(new Location
                {
                    Uri = request.TextDocument.Uri,
                    Range = SemanticLookup.ToRange(structSym.Declaration.Identifier),
                });
            }
        }

        return locations.ToArray();
    }

    private Location[] ComputeTypeDefinition(DocumentContent content, TypeDefinitionParams request)
    {
        var offset = SemanticLookup.ToOffset(content, request.Position);
        var token = SemanticLookup.FindTokenAt(content.SyntaxTree, offset);
        if (token == null || token.Kind != SyntaxKind.IdentifierToken)
        {
            return Array.Empty<Location>();
        }

        var compilation = TryGetCompilation(content);
        if (compilation == null)
        {
            return Array.Empty<Location>();
        }

        var symbol = SemanticLookup.ResolveSymbol(compilation, token);
        TypeSymbol typeSymbol = symbol switch
        {
            ParameterSymbol ps => ps.Type,
            VariableSymbol vs => vs.Type,
            FunctionSymbol fs => fs.Type,
            _ => null,
        };

        if (typeSymbol == null)
        {
            return Array.Empty<Location>();
        }

        var firstRef = SemanticLookup.FindReferences(compilation, typeSymbol).FirstOrDefault();
        if (firstRef == null)
        {
            return Array.Empty<Location>();
        }

        return new[]
        {
            new Location
            {
                Uri = request.TextDocument.Uri,
                Range = SemanticLookup.ToRange(firstRef),
            },
        };
    }

    private LinkedEditingRanges ComputeLinkedEditingRanges(DocumentContent content, LinkedEditingRangeParams request)
    {
        var tree = content.SyntaxTree;
        var offset = SemanticLookup.ToOffset(content, request.Position);
        var token = SemanticLookup.FindTokenAt(tree, offset);
        if (token == null || token.Kind != SyntaxKind.IdentifierToken)
        {
            return null;
        }

        var compilation = TryGetCompilation(content);
        if (compilation == null)
        {
            return null;
        }

        var symbol = SemanticLookup.ResolveSymbol(compilation, token);
        if (!SemanticLookup.CanRename(symbol))
        {
            return null;
        }

        var references = SemanticLookup.FindReferences(compilation, symbol).ToList();
        if (references.Count == 0)
        {
            return null;
        }

        return new LinkedEditingRanges
        {
            Ranges = references.Select(SemanticLookup.ToRange).ToList(),
            WordPattern = @"[a-zA-Z_]\w*",
        };
    }

    private void HandleProjectFileChange(string filePath, FileChangeType changeType)
    {
        switch (changeType)
        {
            case FileChangeType.Created:
                var discovered = ProjectDiscovery.DiscoverProject(filePath);
                if (discovered != null)
                {
                    var project = this.workspaceState.AddProject(discovered.ProjectFilePath);
                    project.ProjectReferences = discovered.ProjectReferences;
                    project.ReferenceSourcePath = discovered.ReferenceSourcePath;
                    project.References = discovered.References;
                    foreach (var source in discovered.SourceFiles)
                    {
                        project.AddFileFromDisk(source);
                        this.workspaceState.RegisterFile(source, project);
                    }
                }

                break;

            case FileChangeType.Changed:
                var existing = this.workspaceState.GetProject(filePath);
                var rediscovered = existing != null ? ProjectDiscovery.DiscoverProject(filePath) : null;
                if (rediscovered != null)
                {
                    existing.ProjectReferences = rediscovered.ProjectReferences;
                    existing.ReferenceSourcePath = rediscovered.ReferenceSourcePath;
                    existing.References = rediscovered.References;
                    foreach (var source in rediscovered.SourceFiles)
                    {
                        if (!existing.ContainsFile(source))
                        {
                            existing.AddFileFromDisk(source);
                            this.workspaceState.RegisterFile(source, existing);
                        }
                    }

                    foreach (var oldFile in existing.SourceFiles.ToList())
                    {
                        if (!rediscovered.SourceFiles.Contains(oldFile))
                        {
                            existing.RemoveFile(oldFile);
                            this.workspaceState.UnregisterFile(oldFile);
                        }
                    }
                }

                break;

            case FileChangeType.Deleted:
                this.workspaceState.RemoveProject(filePath);
                break;
        }
    }

    private void HandleSourceFileChange(string filePath, FileChangeType changeType)
    {
        switch (changeType)
        {
            case FileChangeType.Created:
                var project = this.FindOwningProject(filePath);
                if (project != null)
                {
                    project.AddFileFromDisk(filePath);
                    this.workspaceState.RegisterFile(filePath, project);
                }

                break;

            case FileChangeType.Deleted:
                var owning = this.workspaceState.GetProjectForFile(filePath);
                if (owning != null)
                {
                    owning.RemoveFile(filePath);
                    this.workspaceState.UnregisterFile(filePath);
                }

                break;
        }
    }

    private ProjectState FindOwningProject(string filePath)
    {
        var fileDir = Path.GetDirectoryName(Path.GetFullPath(filePath));
        foreach (var project in this.workspaceState.Projects)
        {
            if (fileDir != null && fileDir.StartsWith(project.ProjectDirectory, StringComparison.OrdinalIgnoreCase))
            {
                return project;
            }
        }

        return this.workspaceState.GetOrCreateImplicitProject();
    }

    private static GSharp.Core.CodeAnalysis.Compilation.Compilation TryGetCompilation(DocumentContent content)
    {
        try
        {
            return content.Project?.GetCompilation()
                ?? new GSharp.Core.CodeAnalysis.Compilation.Compilation(content.SyntaxTree);
        }
        catch
        {
            return null;
        }
    }
}
